components_ChatWidget_tsx = '\'use client\'\n\nimport { useState, useEffect, useRef } from \'react\'\nimport { MessageCircle, X, Send, Minimize2 } from \'lucide-react\'\nimport { supabase } from \'@/lib/supabase\'\nimport { useAuth } from \'@/lib/auth-context\'\n\ntype Message = {\n  id: string\n  user_id: string\n  message: string\n  sender: \'user\' | \'admin\'\n  read: boolean\n  created_at: string\n}\n\nconst AUTO_REPLIES = [\n  "Hi there! 👋 Welcome to BIG EARN. I\'m here to help. What would you like to know?",\n  "Great question! Our team typically responds within a few minutes. Is there anything specific about our investment plans you\'d like to know?",\n  "Thank you for reaching out! Our support team is available 24/7. How can we assist you today?",\n  "We\'re glad you\'re here! BIG EARN has paid out over $4.2M to investors with zero defaults since 2019. What can I help you with?",\n]\n\nexport default function ChatWidget() {\n  const { user } = useAuth()\n  const [open, setOpen] = useState(false)\n  const [messages, setMessages] = useState<Message[]>([])\n  const [input, setInput] = useState(\'\')\n  const [sending, setSending] = useState(false)\n  const [unread, setUnread] = useState(0)\n  const [guestName, setGuestName] = useState(\'\')\n  const [guestStarted, setGuestStarted] = useState(false)\n  const bottomRef = useRef<HTMLDivElement>(null)\n  const channelRef = useRef<any>(null)\n\n  useEffect(() => {\n    if (!open) return\n    if (user) {\n      fetchMessages()\n      subscribeToMessages()\n    }\n    return () => {\n      if (channelRef.current) supabase.removeChannel(channelRef.current)\n    }\n  }, [open, user])\n\n  useEffect(() => {\n    bottomRef.current?.scrollIntoView({ behavior: \'smooth\' })\n  }, [messages])\n\n  async function fetchMessages() {\n    if (!user) return\n    const { data } = await supabase\n      .from(\'chats\')\n      .select(\'*\')\n      .eq(\'user_id\', user.id)\n      .order(\'created_at\', { ascending: true })\n      .limit(50)\n    if (data) setMessages(data as Message[])\n\n    // Mark admin messages as read\n    await supabase.from(\'chats\').update({ read: true })\n      .eq(\'user_id\', user.id).eq(\'sender\', \'admin\').eq(\'read\', false)\n    setUnread(0)\n  }\n\n  function subscribeToMessages() {\n    if (!user) return\n    if (channelRef.current) supabase.removeChannel(channelRef.current)\n    const channel = supabase\n      .channel(`chat-${user.id}`)\n      .on(\'postgres_changes\', {\n        event: \'INSERT\', schema: \'public\', table: \'chats\',\n        filter: `user_id=eq.${user.id}`\n      }, (payload) => {\n        const msg = payload.new as Message\n        setMessages(prev => [...prev, msg])\n        if (msg.sender === \'admin\' && !open) setUnread(n => n + 1)\n      })\n      .subscribe()\n    channelRef.current = channel\n  }\n\n  async function sendMessage() {\n    if (!input.trim() || !user) return\n    setSending(true)\n    const text = input.trim()\n    setInput(\'\')\n\n    await supabase.from(\'chats\').insert({\n      user_id: user.id,\n      message: text,\n      sender: \'user\',\n      read: false,\n    })\n    setSending(false)\n  }\n\n  function handleGuestStart() {\n    if (!guestName.trim()) return\n    setGuestStarted(true)\n    setMessages([{\n      id: \'1\', user_id: \'guest\', message: AUTO_REPLIES[0],\n      sender: \'admin\', read: true, created_at: new Date().toISOString()\n    }])\n  }\n\n  function handleGuestSend() {\n    if (!input.trim()) return\n    const text = input.trim()\n    setInput(\'\')\n    const userMsg: Message = {\n      id: Date.now().toString(), user_id: \'guest\',\n      message: text, sender: \'user\', read: true,\n      created_at: new Date().toISOString()\n    }\n    setMessages(prev => [...prev, userMsg])\n\n    // Auto reply after 1.5s\n    setTimeout(() => {\n      const reply = AUTO_REPLIES[Math.floor(Math.random() * AUTO_REPLIES.length)]\n      setMessages(prev => [...prev, {\n        id: (Date.now() + 1).toString(), user_id: \'guest\',\n        message: reply, sender: \'admin\', read: true,\n        created_at: new Date().toISOString()\n      }])\n    }, 1500)\n  }\n\n  return (\n    <>\n      {/* Floating button */}\n      <div style={{ position: \'fixed\', bottom: 86, right: 16, zIndex: 100 }}>\n        {!open && (\n          <button\n            onClick={() => setOpen(true)}\n            style={{\n              width: 52, height: 52, borderRadius: \'50%\',\n              background: \'linear-gradient(135deg, #f5c842, #e6b800)\',\n              border: \'none\', cursor: \'pointer\',\n              display: \'flex\', alignItems: \'center\', justifyContent: \'center\',\n              boxShadow: \'0 4px 20px rgba(245,200,66,0.5)\',\n              position: \'relative\'\n            }}\n          >\n            <MessageCircle size={22} color="#050810" />\n            {unread > 0 && (\n              <span style={{\n                position: \'absolute\', top: -3, right: -3,\n                width: 18, height: 18, borderRadius: \'50%\',\n                background: \'#f87171\', color: \'#fff\',\n                fontSize: \'0.6rem\', fontWeight: 700,\n                display: \'flex\', alignItems: \'center\', justifyContent: \'center\'\n              }}>{unread}</span>\n            )}\n          </button>\n        )}\n      </div>\n\n      {/* Chat window */}\n      {open && (\n        <div style={{\n          position: \'fixed\', bottom: 80, right: 10, left: 10,\n          maxWidth: 380, margin: \'0 auto\',\n          background: \'#0a0f1e\', border: \'1px solid rgba(245,200,66,0.25)\',\n          borderRadius: 18, zIndex: 100, overflow: \'hidden\',\n          boxShadow: \'0 8px 40px rgba(0,0,0,0.6)\',\n          display: \'flex\', flexDirection: \'column\', height: 420\n        }}>\n          {/* Header */}\n          <div style={{\n            background: \'linear-gradient(135deg, #f5c842, #e6b800)\',\n            padding: \'14px 16px\',\n            display: \'flex\', justifyContent: \'space-between\', alignItems: \'center\',\n            flexShrink: 0\n          }}>\n            <div style={{ display: \'flex\', alignItems: \'center\', gap: 10 }}>\n              <div style={{ width: 34, height: 34, borderRadius: \'50%\', background: \'#050810\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', fontSize: \'1.1rem\' }}>👩🏽\u200d💼</div>\n              <div>\n                <div style={{ fontFamily: \'var(--font-display)\', fontSize: \'0.95rem\', color: \'#050810\', fontWeight: 700 }}>BIG EARN SUPPORT</div>\n                <div style={{ fontSize: \'0.65rem\', color: \'rgba(0,0,0,0.6)\', display: \'flex\', alignItems: \'center\', gap: 4 }}>\n                  <span style={{ width: 6, height: 6, borderRadius: \'50%\', background: \'#16a34a\', display: \'inline-block\' }} />\n                  Online · Typically replies instantly\n                </div>\n              </div>\n            </div>\n            <button onClick={() => setOpen(false)} style={{ background: \'none\', border: \'none\', cursor: \'pointer\', color: \'#050810\', padding: 4 }}>\n              <X size={18} />\n            </button>\n          </div>\n\n          {/* Guest name prompt */}\n          {!user && !guestStarted ? (\n            <div style={{ flex: 1, display: \'flex\', flexDirection: \'column\', alignItems: \'center\', justifyContent: \'center\', padding: \'24px 20px\', gap: 14 }}>\n              <div style={{ fontSize: \'2rem\' }}>💬</div>\n              <div style={{ textAlign: \'center\' }}>\n                <div style={{ fontWeight: 600, color: \'#e8eaf0\', marginBottom: 6 }}>Welcome to Support</div>\n                <div style={{ fontSize: \'0.8rem\', color: \'rgba(255,255,255,0.45)\', lineHeight: 1.6 }}>Enter your name to start chatting with our support team</div>\n              </div>\n              <input\n                className="input-field"\n                placeholder="Your name"\n                value={guestName}\n                onChange={e => setGuestName(e.target.value)}\n                onKeyDown={e => e.key === \'Enter\' && handleGuestStart()}\n                style={{ width: \'100%\' }}\n              />\n              <button className="btn-gold" onClick={handleGuestStart} style={{ width: \'100%\', padding: \'12px\', fontSize: \'0.9rem\' }}>\n                START CHAT\n              </button>\n              <p style={{ fontSize: \'0.72rem\', color: \'rgba(255,255,255,0.3)\', textAlign: \'center\' }}>\n                Or <a href="/auth/login" style={{ color: \'#f5c842\', textDecoration: \'none\' }}>login</a> for full support access\n              </p>\n            </div>\n          ) : (\n            <>\n              {/* Messages */}\n              <div style={{ flex: 1, overflowY: \'auto\', padding: \'14px 14px 8px\' }}>\n                {/* Welcome message */}\n                {(user && messages.length === 0) && (\n                  <div style={{ textAlign: \'center\', marginBottom: 16 }}>\n                    <div style={{ fontSize: \'1.8rem\', marginBottom: 6 }}>👋</div>\n                    <div style={{ fontSize: \'0.8rem\', color: \'rgba(255,255,255,0.45)\', lineHeight: 1.6 }}>\n                      Hi {user.full_name?.split(\' \')[0]}! How can we help you today?\n                    </div>\n                    {/* Quick reply buttons */}\n                    <div style={{ display: \'flex\', flexDirection: \'column\', gap: 7, marginTop: 14 }}>\n                      {[\'How do I deposit funds?\', \'When will my withdrawal arrive?\', \'Which plan is best for me?\', \'I need help with my account\'].map((q, i) => (\n                        <button key={i} onClick={() => setInput(q)} style={{ padding: \'8px 12px\', background: \'rgba(245,200,66,0.08)\', border: \'1px solid rgba(245,200,66,0.25)\', borderRadius: 10, color: \'rgba(255,255,255,0.7)\', fontSize: \'0.76rem\', cursor: \'pointer\', textAlign: \'left\' }}>\n                          {q}\n                        </button>\n                      ))}\n                    </div>\n                  </div>\n                )}\n\n                {messages.map(msg => (\n                  <div key={msg.id} style={{ display: \'flex\', justifyContent: msg.sender === \'user\' ? \'flex-end\' : \'flex-start\', marginBottom: 10 }}>\n                    {msg.sender === \'admin\' && (\n                      <div style={{ width: 26, height: 26, borderRadius: \'50%\', background: \'rgba(245,200,66,0.15)\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', fontSize: \'0.9rem\', flexShrink: 0, marginRight: 7, alignSelf: \'flex-end\' }}>👩🏽\u200d💼</div>\n                    )}\n                    <div style={{\n                      maxWidth: \'72%\', padding: \'9px 12px\', borderRadius: msg.sender === \'user\' ? \'14px 14px 4px 14px\' : \'14px 14px 14px 4px\',\n                      background: msg.sender === \'user\' ? \'linear-gradient(135deg, #f5c842, #e6b800)\' : \'rgba(255,255,255,0.07)\',\n                      color: msg.sender === \'user\' ? \'#050810\' : \'#e8eaf0\',\n                      fontSize: \'0.82rem\', lineHeight: 1.55\n                    }}>\n                      {msg.message}\n                      <div style={{ fontSize: \'0.6rem\', color: msg.sender === \'user\' ? \'rgba(0,0,0,0.4)\' : \'rgba(255,255,255,0.3)\', marginTop: 4, textAlign: \'right\' }}>\n                        {new Date(msg.created_at).toLocaleTimeString([], { hour: \'2-digit\', minute: \'2-digit\' })}\n                      </div>\n                    </div>\n                  </div>\n                ))}\n                <div ref={bottomRef} />\n              </div>\n\n              {/* Input */}\n              <div style={{ padding: \'10px 12px\', borderTop: \'1px solid rgba(255,255,255,0.07)\', display: \'flex\', gap: 8, alignItems: \'center\', flexShrink: 0 }}>\n                <input\n                  className="input-field"\n                  placeholder="Type a message..."\n                  value={input}\n                  onChange={e => setInput(e.target.value)}\n                  onKeyDown={e => e.key === \'Enter\' && (user ? sendMessage() : handleGuestSend())}\n                  style={{ flex: 1, padding: \'10px 14px\', fontSize: \'0.82rem\' }}\n                />\n                <button\n                  onClick={user ? sendMessage : handleGuestSend}\n                  disabled={!input.trim() || sending}\n                  style={{ width: 38, height: 38, borderRadius: \'50%\', background: input.trim() ? \'linear-gradient(135deg, #f5c842, #e6b800)\' : \'rgba(255,255,255,0.08)\', border: \'none\', cursor: input.trim() ? \'pointer\' : \'default\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0, transition: \'all 0.2s\' }}\n                >\n                  <Send size={15} color={input.trim() ? \'#050810\' : \'rgba(255,255,255,0.3)\'} />\n                </button>\n              </div>\n            </>\n          )}\n        </div>\n      )}\n    </>\n  )\n}\n'
os.makedirs(os.path.dirname('components/ChatWidget.tsx') or '.', exist_ok=True)
open('components/ChatWidget.tsx','w').write(components_ChatWidget_tsx)
print('wrote components/ChatWidget.tsx')
components_DashboardChat_tsx = '\'use client\'\n\nimport { useState, useEffect, useRef } from \'react\'\nimport { MessageCircle, Send, X } from \'lucide-react\'\nimport { supabase } from \'@/lib/supabase\'\nimport { useAuth } from \'@/lib/auth-context\'\n\ntype Message = {\n  id: string\n  user_id: string\n  message: string\n  sender: \'user\' | \'admin\'\n  read: boolean\n  created_at: string\n}\n\nexport default function DashboardChat() {\n  const { user } = useAuth()\n  const [open, setOpen] = useState(false)\n  const [messages, setMessages] = useState<Message[]>([])\n  const [input, setInput] = useState(\'\')\n  const [sending, setSending] = useState(false)\n  const [unread, setUnread] = useState(0)\n  const bottomRef = useRef<HTMLDivElement>(null)\n  const channelRef = useRef<any>(null)\n\n  useEffect(() => {\n    if (!user) return\n    fetchMessages()\n    subscribeMessages()\n    return () => { if (channelRef.current) supabase.removeChannel(channelRef.current) }\n  }, [user?.id])\n\n  useEffect(() => {\n    if (open) {\n      bottomRef.current?.scrollIntoView({ behavior: \'smooth\' })\n      markRead()\n    }\n  }, [messages, open])\n\n  async function fetchMessages() {\n    if (!user) return\n    const { data } = await supabase\n      .from(\'chats\').select(\'*\').eq(\'user_id\', user.id)\n      .order(\'created_at\', { ascending: true }).limit(100)\n    if (data) setMessages(data as Message[])\n    const unreadCount = (data as Message[] ?? []).filter(m => m.sender === \'admin\' && !m.read).length\n    setUnread(unreadCount)\n  }\n\n  async function markRead() {\n    if (!user) return\n    await supabase.from(\'chats\').update({ read: true })\n      .eq(\'user_id\', user.id).eq(\'sender\', \'admin\').eq(\'read\', false)\n    setUnread(0)\n  }\n\n  function subscribeMessages() {\n    if (!user) return\n    if (channelRef.current) supabase.removeChannel(channelRef.current)\n    const ch = supabase.channel(`dash-chat-${user.id}`)\n      .on(\'postgres_changes\', { event: \'INSERT\', schema: \'public\', table: \'chats\', filter: `user_id=eq.${user.id}` },\n        (payload) => {\n          const msg = payload.new as Message\n          setMessages(prev => [...prev, msg])\n          if (msg.sender === \'admin\') {\n            if (open) markRead()\n            else setUnread(n => n + 1)\n          }\n        })\n      .subscribe()\n    channelRef.current = ch\n  }\n\n  async function sendMessage() {\n    if (!input.trim() || !user || sending) return\n    setSending(true)\n    const text = input.trim()\n    setInput(\'\')\n    await supabase.from(\'chats\').insert({ user_id: user.id, message: text, sender: \'user\', read: false })\n    setSending(false)\n  }\n\n  return (\n    <>\n      {/* Floating chat button — above bottom nav */}\n      <div style={{ position: \'fixed\', bottom: 82, right: 16, zIndex: 35 }}>\n        <button\n          onClick={() => { setOpen(!open); if (!open) markRead() }}\n          style={{ width: 50, height: 50, borderRadius: \'50%\', background: open ? \'#1a2540\' : \'linear-gradient(135deg, #f5c842, #e6b800)\', border: open ? \'1px solid rgba(245,200,66,0.4)\' : \'none\', cursor: \'pointer\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', boxShadow: \'0 4px 18px rgba(245,200,66,0.35)\', position: \'relative\', transition: \'all 0.2s\' }}\n        >\n          {open ? <X size={20} color="#f5c842" /> : <MessageCircle size={20} color="#050810" />}\n          {!open && unread > 0 && (\n            <span style={{ position: \'absolute\', top: -3, right: -3, width: 17, height: 17, borderRadius: \'50%\', background: \'#f87171\', color: \'#fff\', fontSize: \'0.58rem\', fontWeight: 700, display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>{unread}</span>\n          )}\n        </button>\n      </div>\n\n      {/* Chat panel */}\n      {open && (\n        <div style={{ position: \'fixed\', bottom: 140, right: 10, left: 10, maxWidth: 400, margin: \'0 auto\', background: \'#0a0f1e\', border: \'1px solid rgba(245,200,66,0.2)\', borderRadius: 18, zIndex: 35, overflow: \'hidden\', boxShadow: \'0 8px 40px rgba(0,0,0,0.7)\', display: \'flex\', flexDirection: \'column\', height: 400 }}>\n          {/* Header */}\n          <div style={{ background: \'linear-gradient(135deg, #f5c842, #e6b800)\', padding: \'12px 16px\', display: \'flex\', alignItems: \'center\', gap: 10, flexShrink: 0 }}>\n            <div style={{ width: 32, height: 32, borderRadius: \'50%\', background: \'#050810\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', fontSize: \'1rem\' }}>👩🏽\u200d💼</div>\n            <div>\n              <div style={{ fontFamily: \'var(--font-display)\', fontSize: \'0.9rem\', color: \'#050810\', fontWeight: 700 }}>SUPPORT TEAM</div>\n              <div style={{ fontSize: \'0.62rem\', color: \'rgba(0,0,0,0.55)\', display: \'flex\', alignItems: \'center\', gap: 4 }}>\n                <span style={{ width: 5, height: 5, borderRadius: \'50%\', background: \'#16a34a\', display: \'inline-block\' }} /> Online 24/7\n              </div>\n            </div>\n          </div>\n\n          {/* Messages */}\n          <div style={{ flex: 1, overflowY: \'auto\', padding: \'12px\' }}>\n            {messages.length === 0 && (\n              <div style={{ textAlign: \'center\', padding: \'20px 10px\' }}>\n                <div style={{ fontSize: \'1.8rem\', marginBottom: 8 }}>💬</div>\n                <div style={{ fontSize: \'0.82rem\', color: \'rgba(255,255,255,0.5)\', lineHeight: 1.6, marginBottom: 14 }}>\n                  Hi {user?.full_name?.split(\' \')[0]}! Our support team is here 24/7. What can we help you with?\n                </div>\n                <div style={{ display: \'flex\', flexDirection: \'column\', gap: 7 }}>\n                  {[\'How do I make a deposit?\', \'When will my withdrawal arrive?\', \'Which investment plan is best?\', \'I have an account issue\'].map((q, i) => (\n                    <button key={i} onClick={() => setInput(q)} style={{ padding: \'8px 12px\', background: \'rgba(245,200,66,0.07)\', border: \'1px solid rgba(245,200,66,0.2)\', borderRadius: 10, color: \'rgba(255,255,255,0.65)\', fontSize: \'0.75rem\', cursor: \'pointer\', textAlign: \'left\' }}>\n                      {q}\n                    </button>\n                  ))}\n                </div>\n              </div>\n            )}\n\n            {messages.map(msg => (\n              <div key={msg.id} style={{ display: \'flex\', justifyContent: msg.sender === \'user\' ? \'flex-end\' : \'flex-start\', marginBottom: 9 }}>\n                {msg.sender === \'admin\' && (\n                  <div style={{ width: 24, height: 24, borderRadius: \'50%\', background: \'rgba(245,200,66,0.15)\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', fontSize: \'0.8rem\', flexShrink: 0, marginRight: 6, alignSelf: \'flex-end\' }}>👩🏽\u200d💼</div>\n                )}\n                <div style={{ maxWidth: \'74%\', padding: \'9px 12px\', borderRadius: msg.sender === \'user\' ? \'13px 13px 3px 13px\' : \'13px 13px 13px 3px\', background: msg.sender === \'user\' ? \'linear-gradient(135deg, #f5c842, #e6b800)\' : \'rgba(255,255,255,0.07)\', color: msg.sender === \'user\' ? \'#050810\' : \'#e8eaf0\', fontSize: \'0.8rem\', lineHeight: 1.55 }}>\n                  {msg.message}\n                  <div style={{ fontSize: \'0.58rem\', color: msg.sender === \'user\' ? \'rgba(0,0,0,0.4)\' : \'rgba(255,255,255,0.28)\', marginTop: 3, textAlign: \'right\' }}>\n                    {new Date(msg.created_at).toLocaleTimeString([], { hour: \'2-digit\', minute: \'2-digit\' })}\n                  </div>\n                </div>\n              </div>\n            ))}\n            <div ref={bottomRef} />\n          </div>\n\n          {/* Input */}\n          <div style={{ padding: \'9px 11px\', borderTop: \'1px solid rgba(255,255,255,0.07)\', display: \'flex\', gap: 7, alignItems: \'center\', flexShrink: 0 }}>\n            <input className="input-field" placeholder="Type a message..." value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === \'Enter\' && sendMessage()} style={{ flex: 1, padding: \'9px 13px\', fontSize: \'0.8rem\' }} />\n            <button onClick={sendMessage} disabled={!input.trim() || sending} style={{ width: 36, height: 36, borderRadius: \'50%\', background: input.trim() ? \'linear-gradient(135deg, #f5c842, #e6b800)\' : \'rgba(255,255,255,0.07)\', border: \'none\', cursor: input.trim() ? \'pointer\' : \'default\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0, transition: \'all 0.2s\' }}>\n              <Send size={14} color={input.trim() ? \'#050810\' : \'rgba(255,255,255,0.25)\'} />\n            </button>\n          </div>\n        </div>\n      )}\n    </>\n  )\n}\n'
