app_dashboard_layout_tsx = '\'use client\'\n\nimport { useEffect, useState, useRef } from \'react\'\nimport Link from \'next/link\'\nimport { usePathname, useRouter } from \'next/navigation\'\nimport { useAuth } from \'@/lib/auth-context\'\nimport { supabase, Notification } from \'@/lib/supabase\'\nimport {\n  LayoutDashboard, ArrowDownCircle, ArrowUpCircle, TrendingUp,\n  ShieldCheck, Bell, LogOut, Menu, X, User\n} from \'lucide-react\'\nimport DashboardChat from \'@/components/DashboardChat\'\n\nconst navItems = [\n  { href: \'/dashboard/main\', label: \'DASHBOARD\', icon: LayoutDashboard },\n  { href: \'/dashboard/deposit\', label: \'DEPOSIT\', icon: ArrowDownCircle },\n  { href: \'/dashboard/withdraw\', label: \'WITHDRAW\', icon: ArrowUpCircle },\n  { href: \'/dashboard/invest\', label: \'INVEST\', icon: TrendingUp },\n]\n\nconst ADMIN_PASSWORD = \'masa234\'\n\nexport default function DashboardLayout({ children }: { children: React.ReactNode }) {\n  const { user, isAdmin, signOut, loading } = useAuth()\n  const router = useRouter()\n  const pathname = usePathname()\n  const [sidebarOpen, setSidebarOpen] = useState(false)\n  const [notifications, setNotifications] = useState<Notification[]>([])\n  const [notifOpen, setNotifOpen] = useState(false)\n  const [adminUnlock, setAdminUnlock] = useState(false)\n  const [adminPassInput, setAdminPassInput] = useState(\'\')\n  const [adminPassError, setAdminPassError] = useState(false)\n  const channelRef = useRef<any>(null)\n  const unreadCount = notifications.filter(n => !n.read).length\n\n  useEffect(() => {\n    if (!loading && !user) router.push(\'/auth/login\')\n  }, [user, loading])\n\n  useEffect(() => {\n    if (!user?.id) return\n\n    fetchNotifications()\n\n    // Clean up previous channel\n    if (channelRef.current) {\n      supabase.removeChannel(channelRef.current)\n    }\n\n    // New realtime channel\n    const channel = supabase\n      .channel(`notif-${user.id}`)\n      .on(\'postgres_changes\', {\n        event: \'INSERT\',\n        schema: \'public\',\n        table: \'notifications\',\n      }, (payload) => {\n        const n = payload.new as Notification\n        // Only add if it\'s for this user or broadcast\n        if (n.user_id === user.id || n.is_broadcast) {\n          setNotifications(prev => [n, ...prev])\n        }\n      })\n      .subscribe()\n\n    channelRef.current = channel\n\n    return () => {\n      if (channelRef.current) {\n        supabase.removeChannel(channelRef.current)\n        channelRef.current = null\n      }\n    }\n  }, [user?.id])\n\n  async function fetchNotifications() {\n    if (!user?.id) return\n    try {\n      const { data } = await supabase\n        .from(\'notifications\')\n        .select(\'*\')\n        .or(`user_id.eq.${user.id},is_broadcast.eq.true`)\n        .order(\'created_at\', { ascending: false })\n        .limit(20)\n      if (data) setNotifications(data as Notification[])\n    } catch (e) {\n      console.error(\'Notifications fetch error:\', e)\n    }\n  }\n\n  async function markAllRead() {\n    if (!user?.id) return\n    setNotifications(prev => prev.map(n => ({ ...n, read: true })))\n    await supabase\n      .from(\'notifications\')\n      .update({ read: true })\n      .or(`user_id.eq.${user.id},is_broadcast.eq.true`)\n  }\n\n  function handleAdminAccess() {\n    if (!isAdmin) { alert(\'Admin account required.\'); return }\n    if (adminPassInput === ADMIN_PASSWORD) {\n      setAdminUnlock(false)\n      setAdminPassInput(\'\')\n      setSidebarOpen(false)\n      router.push(\'/dashboard/admin\')\n    } else {\n      setAdminPassError(true)\n      setTimeout(() => setAdminPassError(false), 2000)\n    }\n  }\n\n  if (loading) return (\n    <div style={{ minHeight: \'100vh\', background: \'#050810\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>\n      <div style={{ textAlign: \'center\' }}>\n        <div style={{ fontFamily: \'var(--font-display)\', fontSize: \'2rem\', color: \'#f5c842\', marginBottom: 8 }}>BIG EARN</div>\n        <div style={{ color: \'rgba(255,255,255,0.4)\', fontSize: \'0.9rem\' }}>Loading...</div>\n      </div>\n    </div>\n  )\n\n  if (!user) return null\n\n  return (\n    <div style={{ minHeight: \'100vh\', background: \'#050810\', display: \'flex\', flexDirection: \'column\' }}>\n      {/* TOP BAR */}\n      <header style={{\n        display: \'flex\', alignItems: \'center\', justifyContent: \'space-between\',\n        padding: \'0 16px\', height: 60,\n        background: \'rgba(10,15,30,0.95)\', backdropFilter: \'blur(20px)\',\n        borderBottom: \'1px solid rgba(245,200,66,0.1)\',\n        position: \'sticky\', top: 0, zIndex: 40\n      }}>\n        <button onClick={() => setSidebarOpen(true)} style={{ background: \'none\', border: \'none\', color: \'#e8eaf0\', cursor: \'pointer\', padding: 8 }}>\n          <Menu size={22} />\n        </button>\n        <div style={{ fontFamily: \'var(--font-display)\', fontSize: \'1.5rem\' }}>\n          <span className="gold-text">BIG</span>\n          <span style={{ color: \'#e8eaf0\' }}> EARN</span>\n        </div>\n        <button\n          onClick={() => setNotifOpen(!notifOpen)}\n          style={{ position: \'relative\', background: \'none\', border: \'none\', color: \'#e8eaf0\', cursor: \'pointer\', padding: 8 }}\n        >\n          <Bell size={22} />\n          {unreadCount > 0 && (\n            <span style={{ position: \'absolute\', top: 4, right: 4, width: 16, height: 16, borderRadius: \'50%\', background: \'#f5c842\', color: \'#050810\', fontSize: \'0.6rem\', fontWeight: 700, display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>\n              {unreadCount}\n            </span>\n          )}\n        </button>\n      </header>\n\n      {/* NOTIFICATIONS PANEL */}\n      {notifOpen && (\n        <>\n          <div style={{ position: \'fixed\', inset: 0, zIndex: 45 }} onClick={() => setNotifOpen(false)} />\n          <div style={{\n            position: \'fixed\', top: 60, right: 0, left: 0, maxWidth: 400, margin: \'0 auto\',\n            background: \'#0a0f1e\', border: \'1px solid rgba(245,200,66,0.15)\',\n            borderRadius: \'0 0 16px 16px\', zIndex: 50, maxHeight: \'70vh\', overflowY: \'auto\'\n          }}>\n            <div style={{ padding: \'14px 16px\', display: \'flex\', justifyContent: \'space-between\', alignItems: \'center\', borderBottom: \'1px solid rgba(245,200,66,0.1)\', position: \'sticky\', top: 0, background: \'#0a0f1e\' }}>\n              <span style={{ fontFamily: \'var(--font-display)\', fontSize: \'1.1rem\', color: \'#e8eaf0\' }}>NOTIFICATIONS</span>\n              <button onClick={markAllRead} style={{ background: \'none\', border: \'none\', color: \'#f5c842\', fontSize: \'0.75rem\', cursor: \'pointer\' }}>Mark all read</button>\n            </div>\n            {notifications.length === 0 ? (\n              <div style={{ padding: \'24px\', textAlign: \'center\', color: \'rgba(255,255,255,0.4)\', fontSize: \'0.9rem\' }}>No notifications yet</div>\n            ) : notifications.map(n => (\n              <div key={n.id} style={{ padding: \'14px 16px\', borderBottom: \'1px solid rgba(255,255,255,0.05)\', background: n.read ? \'transparent\' : \'rgba(245,200,66,0.04)\' }}>\n                <div style={{ display: \'flex\', gap: 10, alignItems: \'flex-start\' }}>\n                  <div style={{ width: 8, height: 8, borderRadius: \'50%\', marginTop: 5, flexShrink: 0, background: n.type === \'success\' ? \'#4ade80\' : n.type === \'warning\' ? \'#f5c842\' : n.type === \'alert\' ? \'#f87171\' : \'#60a5fa\' }} />\n                  <div>\n                    <div style={{ fontSize: \'0.85rem\', fontWeight: 600, color: \'#e8eaf0\', marginBottom: 4 }}>{n.title}</div>\n                    <div style={{ fontSize: \'0.8rem\', color: \'rgba(255,255,255,0.5)\', lineHeight: 1.5 }}>{n.message}</div>\n                    <div style={{ fontSize: \'0.7rem\', color: \'rgba(255,255,255,0.3)\', marginTop: 6 }}>{new Date(n.created_at).toLocaleDateString()}</div>\n                  </div>\n                </div>\n              </div>\n            ))}\n          </div>\n        </>\n      )}\n\n      {/* SIDEBAR */}\n      {sidebarOpen && (\n        <div style={{ position: \'fixed\', inset: 0, zIndex: 60, display: \'flex\' }}>\n          <div style={{ position: \'absolute\', left: 0, top: 0, bottom: 0, width: 280, background: \'#0a0f1e\', borderRight: \'1px solid rgba(245,200,66,0.15)\', display: \'flex\', flexDirection: \'column\', overflowY: \'auto\' }}>\n            <div style={{ padding: \'20px\', display: \'flex\', justifyContent: \'space-between\', alignItems: \'center\', borderBottom: \'1px solid rgba(245,200,66,0.1)\' }}>\n              <div style={{ fontFamily: \'var(--font-display)\', fontSize: \'1.6rem\' }}>\n                <span className="gold-text">BIG</span><span style={{ color: \'#e8eaf0\' }}> EARN</span>\n              </div>\n              <button onClick={() => setSidebarOpen(false)} style={{ background: \'none\', border: \'none\', color: \'#e8eaf0\', cursor: \'pointer\' }}><X size={20} /></button>\n            </div>\n\n            <div style={{ padding: \'16px 20px\', borderBottom: \'1px solid rgba(245,200,66,0.08)\' }}>\n              <div style={{ display: \'flex\', gap: 12, alignItems: \'center\' }}>\n                <div style={{ width: 44, height: 44, borderRadius: \'50%\', background: \'rgba(245,200,66,0.15)\', border: \'1px solid rgba(245,200,66,0.3)\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>\n                  <User size={20} color="#f5c842" />\n                </div>\n                <div>\n                  <div style={{ fontSize: \'0.9rem\', fontWeight: 600, color: \'#e8eaf0\' }}>{user.full_name}</div>\n                  <div style={{ fontSize: \'0.75rem\', color: \'rgba(255,255,255,0.4)\' }}>{user.email}</div>\n                </div>\n              </div>\n            </div>\n\n            <nav style={{ flex: 1, padding: \'12px 0\' }}>\n              {navItems.map(item => {\n                const active = pathname === item.href\n                const Icon = item.icon\n                return (\n                  <Link key={item.href} href={item.href} style={{ textDecoration: \'none\' }} onClick={() => setSidebarOpen(false)}>\n                    <div style={{ display: \'flex\', alignItems: \'center\', gap: 14, padding: \'14px 20px\', background: active ? \'rgba(245,200,66,0.08)\' : \'transparent\', borderLeft: active ? \'3px solid #f5c842\' : \'3px solid transparent\', color: active ? \'#f5c842\' : \'rgba(255,255,255,0.6)\' }}>\n                      <Icon size={18} />\n                      <span style={{ fontFamily: \'var(--font-display)\', fontSize: \'1rem\', letterSpacing: \'0.05em\' }}>{item.label}</span>\n                    </div>\n                  </Link>\n                )\n              })}\n\n              {/* Admin Panel */}\n              {isAdmin && (\n                <div>\n                  <button onClick={() => setAdminUnlock(!adminUnlock)} style={{ width: \'100%\', display: \'flex\', alignItems: \'center\', gap: 14, padding: \'14px 20px\', background: \'none\', border: \'none\', color: \'rgba(248,113,113,0.8)\', cursor: \'pointer\', textAlign: \'left\' }}>\n                    <ShieldCheck size={18} />\n                    <span style={{ fontFamily: \'var(--font-display)\', fontSize: \'1rem\', letterSpacing: \'0.05em\' }}>ADMIN PANEL</span>\n                    <span style={{ marginLeft: \'auto\', fontSize: \'0.65rem\', background: \'rgba(248,113,113,0.2)\', border: \'1px solid rgba(248,113,113,0.4)\', color: \'#f87171\', padding: \'2px 8px\', borderRadius: 100 }}>ADMIN</span>\n                  </button>\n                  {adminUnlock && (\n                    <div style={{ margin: \'0 16px 12px\', padding: \'14px\', background: \'rgba(248,113,113,0.07)\', border: \'1px solid rgba(248,113,113,0.2)\', borderRadius: 12 }}>\n             